sql:
SELECT DISTINCT u.team
FROM users u
JOIN models m ON u.user_name = m.created_by;

external_knowledge:
- 'top performing categories' are understood as those with the highest F1-scores;
- 'certain influential user' refers to 'SpecificUserName';
- 'best performance amongst models for each category' means limiting to the top 5 models (by F1-score) for each category.

sql:
SELECT models.model_name, models.model_description
FROM models
INNER JOIN model_deployments ON models.model_id = model_deployments.model_id;

SELECT DISTINCT "class_name" 
FROM "performance_metrics" 
WHERE "f1_score" > 0.6;

SELECT models.model_name, users.user_name 
FROM models 
INNER JOIN users ON models.created_by = users.user_name;
